        CLOTH: { ipa: 'ɔ', example: 'cough, cloth, long', notes: 'Same as LOT; short rounded back' },
        NURSE: { ipa: 'ʌr', example: 'hurt, nurse, word', notes: 'R-coloured mid vowel; rhotic. Quality varies: [ɜr] to [ʌr].' },
        FLEECE: { ipa: 'i', example: 'free, fleece, see', notes: 'Close front monophthong; no length distinction (Scottish Vowel Length Rule governs length by context)' },
