        MOUTH: { ipa: 'ʌu', example: 'now, mouth, how', notes: 'Central onset; more central start than RP /aʊ/' },
        NEAR: { ipa: 'ir', example: 'beer, near, fear', notes: 'Front vowel plus rhotic tap; no centering diphthong' },
        SQUARE: { ipa: 'er', example: 'pair, square, care', notes: 'Mid-front vowel plus rhotic; monophthongal (no glide)' },
